      function CF_10FORMULA0033 return Char is

cursor cur_product is
select value
from pen_dec_fact_types_instance a,
     pen_account b
where a.di_document_type_dec_coce_sr = '1'  
and   a.status 			                 = '1'   
and   a.di_decision_year_sr          = b.di_dt_decision_year 
and   a.di_dec_unit_code_sr          = b.di_dt_dec_unit_code 
and   a.di_dec_incr_seq_no_sr        = b.di_dec_incr_seq_no 
and   a.di_document_type_dec_coce_sr = b.di_dt_document_type_dec_code 
and   b.account_no                   = :p_acc_account_no_dir 
and   a.title_code                   IN ('00372', '00367')
and   a.dec_fact_type_code           = '00499'               --- ΚΑΤΗΓΟΡΙΑ ΣΥΝΤΑΞΗΣ
;

l_product_code VARCHAR2(10);

begin
	
	OPEN  cur_product;
	FETCH cur_product INTO l_product_code;
	CLOSE cur_product;
	
  
  IF l_product_code IS NOT NULL THEN
  	IF l_product_code = '00002' 
  		THEN RETURN 'ΣΥΝΤΑΞΗ ΑΝΑΠΗΡΙΑΣ';
    	ELSE RETURN 'ΣΥΝΤΑΞΗ ΓΗΡΑΤΟΣ';
  	END IF;	
  ELSE
	  IF :CF_IND_PRODUCT = '00002' THEN 
	--	IF :CP_PRODUCT_CODE = '00002' THEN
	  	RETURN 'ΣΥΝΤΑΞΗ ΑΝΑΠΗΡΙΑΣ';
	  ELSE
	  	RETURN 'ΣΥΝΤΑΞΗ ΓΗΡΑΤΟΣ';
	  END IF;	
	 END IF;
	  
end;

