      FUNCTION CF_REDUCTION_267Formula RETURN CHAR IS

SF507_VALUE NUMBER;
SF508_VALUE NUMBER;
SF499_VALUE CHAR(50);

CURSOR CUR_SF499 IS
SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00367' AND
	     A.Dec_Fact_Type_Code = '00499';


CURSOR cur_SF00507 IS 
 SELECT A.VALUE
 FROM  PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00367' AND
	     A.Dec_Fact_Type_Code = '00507';

CURSOR cur_SF00508 IS 
 SELECT A.VALUE
 FROM
       PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
  WHERE
     A.Di_Decision_Year_Sr = B.Di_Dt_Decision_Year AND
     A.Di_Dec_Unit_Code_Sr = B.Di_Dt_Dec_Unit_Code AND
     A.Di_Dec_Incr_Seq_No_Sr = B.Di_Dec_Incr_Seq_No AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No = :P_Acc_Account_No_DIR AND
       A.Title_Code         = '00367' AND
	     A.Dec_Fact_Type_Code = '00508';

v_main_age_reduct_date        DATE;

CURSOR cur_main_age_reduct_date IS
SELECT MAIN_AGE_REDUCT_DATE 
FROM pen_main_age_reduct_date_in_dt
WHERE DEAD_INSURED_ID = :P_Insured_Id;

BEGIN

  OPEN CUR_SF499;
  FETCH CUR_SF499
  INTO SF499_VALUE;
  CLOSE CUR_SF499;

  OPEN cur_main_age_reduct_date;
  FETCH cur_main_age_reduct_date
  INTO v_main_age_reduct_date;
  CLOSE cur_main_age_reduct_date;
  
  IF v_main_age_reduct_date IS NULL THEN
  	v_main_age_reduct_date := :CF_INS_DATE;
  END IF;
  
  --INSERT INTO ERROR_DEBUG VALUES('PRINT','v_main',v_main_age_reduct_date);
  --COMMIT;
 
	IF SF499_VALUE = '00001' THEN 
 		  	OPEN cur_SF00507;
		  	FETCH cur_SF00507
		  	INTO SF507_VALUE;
		  	CLOSE cur_SF00507;

		  IF v_main_age_reduct_date < TO_DATE('1/1/2003','DD/MM/RRRR') THEN

	       IF SF507_VALUE IS NOT NULL THEN 
	   		  	RETURN (TO_CHAR(SF507_VALUE)||'/200');
	       ELSE
	       	  RETURN ' ';
	       END IF;
	    ELSIF v_main_age_reduct_date >= TO_DATE('1/1/2003','DD/MM/RRRR') AND v_main_age_reduct_date < TO_DATE('1/1/2009','DD/MM/RRRR') THEN  
	   
	       IF SF507_VALUE IS NOT NULL THEN 
	   		  	RETURN (TO_CHAR(SF507_VALUE)||'/267');
	       ELSE
	       	  RETURN ' ';
	       END IF;	       
      ELSIF v_main_age_reduct_date >= TO_DATE('1/1/2009','DD/MM/RRRR') THEN  

	        IF SF507_VALUE IS NOT NULL THEN  	
			  	  RETURN (TO_CHAR(SF507_VALUE)||'/200');
	        ELSE
	        	RETURN ' ';
			    END IF;
	       
		  END IF;

	ELSE
 		  	OPEN cur_SF00508;
		  	FETCH cur_SF00508
		  	INTO SF508_VALUE;
		  	CLOSE cur_SF00508;

       IF SF508_VALUE IS NOT NULL THEN  		  	
		  	RETURN TO_CHAR(SF508_VALUE) || '%';
       ELSE
       	RETURN ' ';
       END IF;	
  END IF;
exception when others then return null;

END;

