      FUNCTION CF_DESCRFormula RETURN CHAR IS

V_DEATH DATE;

BEGIN
  SELECT A.DATE_OF_DEATH
  INTO V_DEATH
  FROM REG_INSURED A
  WHERE A.INSURED_ID = :P_INSURED_ID;
  
  IF V_DEATH IS NOT NULL THEN 
    RETURN 'ΗΜΕΡΟΜΗΝΙΑ ΘΑΝΑΤΟΥ                           :';
  ELSE
