 FROM
       PEN_INIT_TRANS_AMOUNT_PER_ACC A,
       PEN_ACCOUNT B
  WHERE A.Account_No = B.Account_No
  AND   B.Account_No = :P_Acc_Account_No_Dir;

-- CHRYS 4/6/2024 
 CURSOR     Cur_Decision IS 
  SELECT      C.Ins_Insured_Id
             ,C.Di_Dec_Incr_Seq_No
             ,C.Di_Dt_Dec_Unit_Code
             ,C.Di_Dt_Decision_Year
             ,C.Di_Dt_Document_Type_Dec_Code
  FROM      PEN_ACCOUNT C
  WHERE     C.Account_No = :p_ACC_account_no_DIR;
 
 I_Insured_Id      PEN_ACCOUNT.INS_Insured_Id%TYPE;
 I_Dec_Incr_Seq_No PEN_ACCOUNT.Di_Dec_Incr_Seq_No%TYPE;
 I_Dec_Unit        PEN_ACCOUNT.Di_Dt_Dec_Unit_Code%TYPE;
 I_Dec_Year        PEN_ACCOUNT.Di_Dt_Decision_Year%TYPE;
 I_Dec_Doc_Type    PEN_ACCOUNT.Di_Dt_Document_Type_Dec_Code%TYPE;


V_VALUE				VARCHAR2(200);
-- END CHRYS 4/6/2024  	

BEGIN

-- CHRYS 4/6/2024
--srw.message(100, ':p_ACC_account_no_DIR; : '||:p_ACC_account_no_DIR);

   OPEN  Cur_Decision;
   FETCH Cur_Decision
   INTO I_Insured_Id,I_Dec_Incr_Seq_No,I_Dec_Unit,I_Dec_Year,I_Dec_Doc_Type;
   CLOSE Cur_Decision;

   V_VALUE := Find_Fact_Sub_Death_Varchar 
                                   (I_Insured_Id,
                                    I_Dec_Year,
                                    I_Dec_Unit,
                                    I_Dec_Incr_Seq_No,
                                    I_Dec_Doc_Type,
                                    0,0,'00001','00367','00505');-- 

  
  
  
  
  IF V_VALUE IS NOT NULL THEN
  	--RETURN (V_VALUE);
  	v_value := V_VALUE;
  
  ELSE
-- END CHRYS 4/6/2024  	

		  OPEN cur_INS_CLASS;
		  FETCH cur_INS_CLASS
		  INTO V_AMOUNT;
		  CLOSE cur_INS_CLASS;
		  
		  --RETURN V_AMOUNT;
     	v_value := V_AMOUNT;
     
 END IF; -- CHRYS 4/6/2024
 
 return v_value;
 EXCEPTION WHEN OTHERS THEN RETURN 0;		  

end;

