	IF (NVL(:CF_20,0) + NVL(:CF_21,0) + NVL(:CF_19,0)) = 0 
  THEN RETURN :CF_32;
	ELSE RETURN(NVL(:CF_20,0) + NVL(:CF_21,0) + NVL(:CF_19,0));
	END IF;		---SPAP 26/04/2021 ΤΟ ΕΒΑΛΑ ΑΥΤΟ ΓΙΑΤΙ ΤΟ ΠΕΔΙΟ ΕΙΧΕ ΕΠΑΝΩ ΤΗΝ CF_32 ΠΟΥ ΑΥΤΗ ΕΧΕΙ ΣΧΟΛΙΑ ΟΤΙ ΠΑΛΙΑ ΕΜΦΑΝΙΖΟΤΑΝ Η CF_22. ΣΕ ΚΑΠΟΙΕΣ ΠΕΡΙΠΤΩΣΕΙΣ 
	          ---ΔΕΝ ΕΜΦΑΝΙΖΕ ΤΟ ΚΑΤΑΒΛΗΤΕΟ ΠΟΣΟ ΜΕ ΤΗΝ CF_32 ΟΠΟΤΕ EBAΛΑ ΑΝ ΑΥΤΗ ΔΕΝ ΕΠΙΣΤΡΕΦΕΙ ΚΑΤΙ ΝΑ ΕΠΙΣΤΡΕΦΕΙ ΤΗΝ CF_32.
end;

      function CF_21Formula return Number is
V_AMOUNT NUMBER;

CURSOR cur_INS_CLASS IS 
 SELECT ADAPODOTIKH_AMT*(:P_PERCENTAGE/100)  ADAPODOTIKH_AMT_MEMBER
FROM PEN_CALC_ADAPOD_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

begin

  OPEN cur_INS_CLASS;
  FETCH cur_INS_CLASS
  INTO V_AMOUNT;
  CLOSE cur_INS_CLASS;
  
  RETURN V_AMOUNT;
  
end;

      function CF_20Formula return Number is
V_AMOUNT NUMBER;

CURSOR cur_INS_CLASS IS 
 SELECT FINAL_NAT_PENSION_AMT*(:P_PERCENTAGE/100) FINAL_NAT_PENSION_AMT_MEMBER
FROM  PEN_CALC_NATIONAL_RESULTS
WHERE ACCOUNT_NO = :P_ACC_ACCOUNT_NO_DIR;

begin

  OPEN cur_INS_CLASS;
  FETCH cur_INS_CLASS
  INTO V_AMOUNT;
  CLOSE cur_INS_CLASS;
  
  RETURN V_AMOUNT;
  
end;

      function CF_19Formula return Number is
