      function CF_16Formula return Number is
v_NUM NUMBER;
    
    CURSOR Cur_NUM IS
   SELECT NVL(PERSONAL_DIFFERENCE,0)
FROM PEN_EFKA_PERSONAL_DIFFERENCE
WHERE ACCOUNT_NO =:P_Acc_Account_No_Dir;   

begin
  
  
                 OPEN Cur_NUM;
                  FETCH Cur_NUM
                  INTO v_NUM;
                  CLOSE Cur_NUM;
                  
             RETURN v_NUM;
END ;

