      function CF_13FORMULA0023 return Char is

V_ACCOUNT_METABIB                 VARCHAR2(100);
V_QC_PER_PRODINST_CODE            VARCHAR2(100);
V_UNIT_SR                         VARCHAR2(100);
V_YEAR_SR                         NUMBER;
V_INCR_NO_SR                      NUMBER;

--ΣΤΟΙΧΕΙΑ ΛΟΓΑΡΙΑΣΜΟΥ ΜΕΤΑΒΙΒΑΣΗΣ
CURSOR cur_STOIXEIA_METABIB IS 
 SELECT A.VALUE
 FROM  PEN_DEC_FACT_TYPES_INSTANCE A,
       PEN_ACCOUNT B
 WHERE
     A.Di_Decision_Year_Sr          = B.Di_Dt_Decision_Year          AND
     A.Di_Dec_Unit_Code_Sr          = B.Di_Dt_Dec_Unit_Code          AND
     A.Di_Dec_Incr_Seq_No_Sr        = B.Di_Dec_Incr_Seq_No           AND
     A.Di_Document_Type_Dec_Coce_Sr = B.Di_Dt_Document_Type_Dec_Code AND
     B.Account_No                   = :P_Acc_Account_No_DIR          AND
     A.Title_Code                   = '00656'                        AND
	   A.Dec_Fact_Type_Code           = '00726';

CURSOR cur_FIND_QC IS 
  SELECT QCPRODINS_QC_PER_PRODINST_CODE, DI_DT_DEC_UNIT_CODE, DI_DT_DECISION_YEAR, DI_DEC_INCR_SEQ_NO
  FROM PEN_ACCOUNT 
  WHERE ACCOUNT_NO     = V_ACCOUNT_METABIB
   --AND  INS_INSURED_ID = :P_INSURED_ID
    ;

CURSOR cur_PEN_DEC_DEAD IS
 SELECT TO_CHAR(A.PAYMENT_START_DATE,'DD/MM/YYYY') , A.DEC_INCR_SEQ_NO||'/'||A.DT_DECISION_YEAR
 FROM PEN_DECISION_INSTANCE A
 WHERE A.INS_INSURED_ID        = :P_INSURED_ID
 AND   A.DEC_UNIT_CODE_SR      = V_UNIT_SR
 AND   A.DECISION_YEAR_SR      = V_YEAR_SR
 AND   A.INCR_SEQ_NO_SR        = V_INCR_NO_SR
 AND   A.QC_PER_PRODINST_CODE  = V_QC_PER_PRODINST_CODE
 AND   A.STATUS                = '1'
 AND   A.DECISION_STATE_FLG    = '1'
 AND   A.DECISION_TYPE_FLG     = '0';
  
BEGIN

  OPEN cur_STOIXEIA_METABIB;
  FETCH cur_STOIXEIA_METABIB
  INTO V_ACCOUNT_METABIB;
  CLOSE cur_STOIXEIA_METABIB;
 
  OPEN cur_FIND_QC;
  FETCH cur_FIND_QC
  INTO V_QC_PER_PRODINST_CODE, V_UNIT_SR, V_YEAR_SR, V_INCR_NO_SR;
  CLOSE cur_FIND_QC;
 
  OPEN cur_PEN_DEC_DEAD;
  FETCH cur_PEN_DEC_DEAD
  INTO :DEAD_PAYMENT_START_DATE, :DEAD_DEC_NO;
  CLOSE cur_PEN_DEC_DEAD;
  
  RETURN (:DEAD_DEC_NO);
  
  EXCEPTION WHEN OTHERS THEN RETURN NULL;
  
END;

      function AfterPForm return boolean is

cursor c0 is
select a.ammount 
from pen_account a
where 1=1
and a.di_dt_document_type_dec_code = '1'
and a.di_dt_dec_unit_code          = :p_dt_dec_unit_code
and a.di_dt_decision_year          = :p_dt_decision_year
and a.di_dec_incr_seq_no           = :p_dt_incr_sec_no_sr
and a.acc_account_no               = :P_ACC_ACCOUNT_NO_DIR;

l_pension_amount number;


cursor c1 is
SELECT COM_ORG_BRANCHES.BRANCH_NAME, COM_ORG_BRANCHES.BRANCH_CODE
  FROM REG_INSURED, 
       PEN_APPLICATION_INSTANCES, 
	     COM_ORG_BRANCHES, 
	     PEN_BE_PER_PRODINST, 
	     PEN_PRODUCT_PER_INSTITUTIONS,
	     PEN_PRODUCTS,
	     COM_PENSION_IKA_INSTITUTION
 WHERE PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO=:P_APPL_INCR_SEQ_NO
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE=:P_APPL_UNIT_CODE
   AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001'
   AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR=:P_APPL_YEAR
   AND PEN_APPLICATION_INSTANCES.INSURED_ID=:P_INSURED_ID
   AND REG_INSURED.INSURED_ID=PEN_APPLICATION_INSTANCES.INSURED_ID
   AND PEN_BE_PER_PRODINST.BE_PER_PRODINST_CODE=:P_BE_PER_PRODINST
   AND PEN_BE_PER_PRODINST.PRODUCT_PER_INSTITUTION_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_PER_INSTITUTION_CODE
   AND COM_PENSION_IKA_INSTITUTION.PENSION_IKA_INST_CODE=PEN_PRODUCT_PER_INSTITUTIONS.INSTITUTION_CODE
   AND PEN_PRODUCTS.PRODUCT_CODE=PEN_PRODUCT_PER_INSTITUTIONS.PRODUCT_CODE
   AND COM_ORG_BRANCHES.BRANCH_CODE=:P_DT_DEC_UNIT_CODE_SR;


cursor c2 is
SELECT PEN_DECISION_INSTANCE.E_DEC_YEAR||'/'||PEN_DECISION_INSTANCE.E_DEC_NO||'*' , PEN_DECISION_INSTANCE.E_DEC_NO  ,
	     qual_pension_right_date  
  FROM pen_decision_instance
 where dt_decision_year = :P_DT_DECISION_YEAR
  and  dec_incr_seq_no  = :P_DECISION_NO
  and  dt_dec_unit_code = :P_DT_DEC_UNIT_CODE; 

L_DEC_NO              VARCHAR2(100);
	
begin
  
  open  c0;
  fetch c0 into l_pension_amount;
  close c0;
  
  if l_pension_amount is not null and l_pension_amount <> 0
  	 then :P_PENSION_AMOUNT := l_pension_amount;
  end if;
  
  open c1;
	fetch c1 into :p_branch_name, :P_BRANCH_CODE;
	close c1;
	
	open c2;
	fetch c2 into :p_e_yyyyaa, L_DEC_NO , :P_QUAL_PENSION_RIGHT_DATE;
	close c2;
	
	if L_DEC_NO is not null then 
	   :p_e_yyyyaa :=	'*e-'||:p_e_yyyyaa;
	else
		 :p_e_yyyyaa := null;
	end if;	 
	
  --SRW.MESSAGE(100,'P_Acc_Account_No_Dir : '||:P_Acc_Account_No_Dir);
  return (TRUE);
end;

