      function CF_PENSION_AMOUNTFormula return Number is

-- FOR JIRA HD2024-1287
V_RETURN  NUMBER;
begin
  IF :P_ACC_ACCOUNT_NO = 4769524  THEN
  	V_RETURN := replace(140.23,'.',',');
  ELSE
  	V_RETURN := replace(:P_PENSION_AMOUNT,'.',',');
  END IF;
  
  RETURN (V_RETURN);
  exception when others then return 0; 
end;

function CF_DEPENDENCY_TYPEFormula return Char is
CURSOR C1 IS SELECT --PEN_DECISION_INSTANCE_DEATH.Dependency_Type --PEN_DECISION_INSTANCE_DEATH.Dependency_Type_Dec PEN_DEPENDANT_TYPES.dependency_name FROM PEN_DECISION_INSTANCE_DEATH, PEN_APPLICATION_INSTANCES, PEN_DEPENDANT_TYPES WHERE PEN_APPLICATION_INSTANCES.Pdta_Application_Year =PEN_DECISION_INSTANCE_DEATH.Pdta_Application_Year AND PEN_APPLICATION_INSTANCES.Pdta_Application_Unit_Code =PEN_DECISION_INSTANCE_DEATH.Pdta_Application_Unit_Code AND PEN_APPLICATION_INSTANCES.Application_Incr_Seq_No =PEN_DECISION_INSTANCE_DEATH.Application_Incr_Seq_No AND PEN_APPLICATION_INSTANCES.Pdta_Document_Type_Appl_Code=PEN_DECISION_INSTANCE_DEATH.Pdta_Document_Type_Appl_Code AND PEN_DEPENDANT_TYPES.dependency_type =PEN_DECISION_INSTANCE_DEATH.Dependency_Type_Dec AND PEN_APPLICATION_INSTANCES.APPLICATION_INCR_SEQ_NO =:P_APPL_INCR_SEQ_NO AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_UNIT_CODE =:P_APPL_UNIT_CODE AND PEN_APPLICATION_INSTANCES.PDTA_DOCUMENT_TYPE_APPL_CODE='00001' AND PEN_APPLICATION_INSTANCES.PDTA_APPLICATION_YEAR =:P_APPL_YEAR AND PEN_APPLICATION_INSTANCES.INSURED_ID =:P_INSURED_ID AND PEN_DECISION_INSTANCE_DEATH.DEC_INCR_SEQ_NO_AS =:P_DECISION_NO AND PEN_DECISION_INSTANCE_DEATH.DEC_UNIT_CODE_AS =:P_DT_DEC_UNIT_CODE AND PEN_DECISION_INSTANCE_DEATH.DECISION_YEAR_AS =:P_DT_DECISION_YEAR ;
L_DESCR VARCHAR2(200); begin OPEN C1; FETCH C1 INTO L_DESCR; CLOSE C1; RETURN (L_DESCR); EXCEPTION WHEN OTHERS THEN RETURN NULL; end;
